package pl.rezerwacjasal.rezerwacjasal.views; import com.vaadin.flow.component.grid.Grid; import com.vaadin.flow.component.html.H2; import com.vaadin.flow.component.orderedlayout.VerticalLayout; import com.vaadin.flow.router.*; import jakarta.annotation.security.RolesAllowed; import pl.rezerwacjasal.rezerwacjasal.model.RoomReservation; import pl.rezerwacjasal.rezerwacjasal.service.RoomReservationService; @Route("admin/rooms") @RolesAllowed("ADMIN") public class AdminRoomsView extends VerticalLayout { public AdminRoomsView(RoomReservationService service) { Grid<RoomReservation> grid=new Grid<>(RoomReservation.class,false); grid.addColumn(RoomReservation::getId).setHeader("ID"); grid.addColumn(r -> r.getUser().getLogin()).setHeader("Client"); grid.addColumn(r -> r.getRoom().getName()).setHeader("Room"); grid.addColumn(RoomReservation::getStartTime).setHeader("Start"); grid.addColumn(RoomReservation::getEndTime).setHeader("End"); grid.setItems(service.getAll()); add(new H2("All reservations"), grid); } }
